# Conditional Access: require FIDO2 specifically for shared/kiosk workstations
# Shared machines cannot use WHfB (per-device) -- FIDO2 key travels with the user
import requests

def get_token():
    r = requests.post(
        'https://login.microsoftonline.com/YOUR_TENANT_ID/oauth2/v2.0/token',
        data={
            'grant_type': 'client_credentials',
            'client_id': 'YOUR_APP_ID',
            'client_secret': 'YOUR_SECRET',
            'scope': 'https://graph.microsoft.com/.default',
        }
    )
    return r.json()['access_token']

token = get_token()
headers = {'Authorization': f'Bearer {token}', 'Content-Type': 'application/json'}

# Create custom strength: FIDO2 only (exclude WHfB, Authenticator)
fido2_only_strength = {
    'displayName': 'FIDO2 Only',
    'description': 'Requires a physical FIDO2 security key -- for shared workstations',
    'allowedCombinations': ['fido2']
}
strength_resp = requests.post(
    'https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies',
    headers=headers, json=fido2_only_strength
)
fido2_strength_id = strength_resp.json().get('id')

# CA policy: require FIDO2 on shared workstations (identified by device group)
shared_workstation_policy = {
    'displayName': 'Require FIDO2 on Shared Workstations',
    'state': 'enabledForReportingButNotEnforced',
    'conditions': {
        'users': {
            'includeGroups': ['SHARED-WORKSTATION-USERS-GROUP-ID'],
            'excludeGroups': ['BREAK-GLASS-GROUP-ID']
        },
        'applications': {'includeApplications': ['All']}
    },
    'grantControls': {
        'operator': 'OR',
        'authenticationStrength': {'id': fido2_strength_id}
    }
}
resp = requests.post(
    'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies',
    headers=headers, json=shared_workstation_policy
)
print(f'Shared workstation policy: {resp.json().get("id")}')
